"""Backend-agnostic test doubles for the HTTP client wrapper.

``MockHTTPClient`` implements ``HTTPClientProtocol`` without depending on
``requests`` or ``httpx``, so tests can exercise the frozen protocol surface
(connection close, cookie access, env-trust control, request verbs) regardless
of the backend a check is running on.
"""

from __future__ import annotations

from typing import Any, Iterator, Mapping

__all__ = ['MockHTTPClient']


class MockHTTPClient:
    """Library-agnostic mock HTTP client implementing ``HTTPClientProtocol``.

    Args:
        cookies: initial cookie jar contents.
        trust_env: initial env-trust setting.
        responses: iterable of objects returned, in order, by the request verbs.
    """

    def __init__(
        self,
        cookies: Mapping[str, str] | None = None,
        trust_env: bool = True,
        responses: list[Any] | None = None,
    ):
        self.options: dict[str, Any] = {}
        self.closed = False
        self._cookies = dict(cookies or {})
        self._trust_env = trust_env
        self._responses: Iterator[Any] = iter(responses or [])
        self.requests: list[tuple[str, str, dict[str, Any]]] = []

    def _record(self, method: str, url: str, options: dict[str, Any]) -> Any:
        self.requests.append((method, url, options))
        return next(self._responses, None)

    def get(self, url: str, **options: Any) -> Any:
        return self._record('get', url, options)

    def post(self, url: str, **options: Any) -> Any:
        return self._record('post', url, options)

    def head(self, url: str, **options: Any) -> Any:
        return self._record('head', url, options)

    def put(self, url: str, **options: Any) -> Any:
        return self._record('put', url, options)

    def patch(self, url: str, **options: Any) -> Any:
        return self._record('patch', url, options)

    def delete(self, url: str, **options: Any) -> Any:
        return self._record('delete', url, options)

    def options_method(self, url: str, **options: Any) -> Any:
        return self._record('options', url, options)

    def close(self) -> None:
        self.closed = True

    @property
    def cookies(self) -> Mapping[str, str]:
        return dict(self._cookies)

    @property
    def trust_env(self) -> bool:
        return self._trust_env

    @trust_env.setter
    def trust_env(self, value: bool) -> None:
        self._trust_env = value

